// Validate secret
const secret = $input.first().headers['x-n8n-secret'];
if (secret !== $env.N8N_WEBHOOK_SECRET) {
  throw new Error('Unauthorized');
}
return $input.all();

const req     = $('Fetch Leave Request').first().json[0];
const manager = $('Fetch Manager').first().json[0];
const event   = $('Validate Secret').first().json.body.event;

if (!req || !manager?.wa_number) return [];

const emp  = req.employee;
const lt   = req.leave_type;
const from = new Date(req.start_date).toLocaleDateString('en-IN', { day: 'numeric', month: 'short' });
const to   = new Date(req.end_date).toLocaleDateString('en-IN',   { day: 'numeric', month: 'short' });

let managerMsg = '';
let employeeMsg = '';

if (event === 'leave_applied') {
  managerMsg  = `📅 *Leave Request*\n\n👤 *${emp.full_name}* has applied for leave.\n🏷 ${lt.name}\n📆 ${from} → ${to} (${req.duration_days} day${req.duration_days > 1 ? 's' : ''})\n${req.reason ? `📝 Reason: ${req.reason}` : ''}\n\nReply *approve ${emp.full_name.split(' ')[0].toLowerCase()} leave* to approve or *reject ${emp.full_name.split(' ')[0].toLowerCase()} leave* to reject.`;
  employeeMsg = `📅 Your *${lt.name}* leave request has been submitted!\n📆 ${from} → ${to}\n⏳ Status: *Pending approval*\n\nYour manager will review it shortly.`;
} else if (event === 'leave_approved') {
  employeeMsg = `✅ Your *${lt.name}* leave has been *approved*!\n📆 ${from} → ${to}\nEnjoy your time off! 🌴`;
} else if (event === 'leave_rejected') {
  employeeMsg = `❌ Your *${lt.name}* leave request was *rejected*.\n📆 ${from} → ${to}\n${req.remarks ? `📝 Remarks: ${req.remarks}` : ''}\n\nContact your manager for more information.`;
}

const messages = [];
if (managerMsg && manager.wa_number)  messages.push({ json: { to: manager.wa_number, message: managerMsg } });
if (employeeMsg && emp.wa_number)      messages.push({ json: { to: emp.wa_number,     message: employeeMsg } });

return messages;
